				ExecuteSequenceOnMatchButNoUpdate: executeSequenceOnNoMatchOrUpdate,
				Indices:                           []string{indexKey},
				Body:                              updateByQuery,
				LogContext:                        updateByQuery.LogContext,
			},
		)

		queryModel.CleanUpIndices.Add(indexKey)
		queryModel.AllIndices.Add(indexKey)
	}
}

