func Publish(
	logContext *log.Context,
	opensearchClient repository.NoSqlMgmtRepository,
	consulClient consul.Client,
	sleepUntilTerminated bool,
	rootDir string,
) {
	// Set so that health check comes back healthy
	applicationInfo.SetPublishFinished(true, true)
	processHaltChannel, err := publish(logContext, opensearchClient, consulClient, rootDir)
	if err != nil {
		failTheHealthCheck(logContext, err)
	} else if processHaltChannel == nil {
		log.Infow(logContext, "Gathering aliases complete.")
	} else if err = <-processHaltChannel; err != nil {
		failTheHealthCheck(logContext, err)
	} else {
		log.Infow(logContext, "Publish complete.")
	}

	log.Flush()

	if sleepUntilTerminated && processHaltChannel != nil {
		<-processHaltChannel
	}
}

func publish(
	logContext *log.Context,
	noSqlMgmtRepository repository.NoSqlMgmtRepository,
	consulClient consul.Client,
	scriptRootDir string,
) (actionChanel <-chan error, err error) {
	return consulClient.RunOnceAction(
		logContext,
		publishSyncKey,
		func() error {
			published, err := opensearchInternal.PublishIndices(
				logContext,
				noSqlMgmtRepository,
