    return m.description
}

// MigrationInfo represents metadata about a migration that has been executed
type MigrationInfo struct {
    Name        string    `json:"name"`
    Version     int       `json:"version"`
    ID          string    `json:"id"`
    Description string    `json:"description"`
    ExecutedAt  time.Time `json:"executed_at"`
    DurationMs  int64     `json:"duration_ms"`
}

// Registry maintains the collection of all available migrations
type Registry struct {
    migrations []Migration
    lookup     map[string]Migration
}

// NewRegistry creates a new migration registry
func NewRegistry() *Registry {
    return &Registry{
        migrations: []Migration{},
        lookup:     make(map[string]Migration),
    }
}

// Register adds a migration to the registry
func (r *Registry) Register(m Migration) {
    // Add to lookup map for quick retrieval by ID
    r.lookup[m.ID()] = m

    // Add to ordered slice
    r.migrations = append(r.migrations, m)

    // Sort migrations by name and version
    sort.Slice(r.migrations, func(i, j int) bool {
        if r.migrations[i].Name() != r.migrations[j].Name() {
            return r.migrations[i].Name() < r.migrations[j].Name()
        }
        return r.migrations[i].Version() < r.migrations[j].Version()
    })
}

// GetAll returns all registered migrations in order
func (r *Registry) GetAll() []Migration {
    return r.migrations
}

// Get returns a specific migration by ID
func (r *Registry) Get(id string) (Migration, bool) {
    m, ok := r.lookup[id]
    return m, ok
}

// GetHighestVersionsByName returns a map of migration names to their highest version migrations
func (r *Registry) GetHighestVersionsByName() map[string]Migration {
    result := make(map[string]Migration)

    for _, m := range r.migrations {
        existingMigration, exists := result[m.Name()]

        if !exists || existingMigration.Version() < m.Version() {
            result[m.Name()] = m
        }
    }

    return result
}
```

Changes:
1. Changed `migrations` from a map to a slice to maintain order
2. Added a `lookup` map for quick access by ID
3. Updated `Register` to maintain both the ordered slice and the lookup map
4. Sort migrations in `Register` to ensure consistent ordering by name and version
5. Updated `GetAll` to return the ordered slice

This gives us the best of both worlds - ordered migrations for sequential execution and fast lookups by ID.

