// internal/pkg/data_migration/registry.go
package data_migration

// Registry maintains the collection of all available migrations
type Registry struct {
    migrations []Migration

    // Map from migration name to its latest version
    latestByName map[string]Migration
}

// NewRegistry creates a new migration registry
func NewRegistry() *Registry {
    return &Registry{
        migrations:   []Migration{},
        latestByName: make(map[string]Migration),
    }
}

// Register adds a migration to the registry
// If a migration with the same name already exists, it will be replaced
func (r *Registry) Register(m Migration) {
    name := m.Name()

    // Check if we already have a migration with this name
    existing, exists := r.latestByName[name]

    // If we have an existing migration with this name, replace it
    if exists {
        // Find the existing migration in the slice
        for i, migration := range r.migrations {
            if migration.Name() == name {
                // Replace it in the ordered slice
                r.migrations[i] = m
                break
            }
        }
    } else {
        // This is a new migration, add it to the end
        r.migrations = append(r.migrations, m)
    }

    // Update the latest version map
    r.latestByName[name] = m
}

// GetAll returns all registered migrations in registration order
func (r *Registry) GetAll() []Migration {
    return r.migrations
}

// Get returns a specific migration by name
func (r *Registry) Get(name string) (Migration, bool) {
    m, ok := r.latestByName[name]
    return m, ok
}

// GetByID returns a specific migration by ID (name:version)
func (r *Registry) GetByID(id string) (Migration, bool) {
    for _, m := range r.migrations {
        if m.ID() == id {
            return m, true
        }
    }
    return nil, false
}
