	_, exists := migrations[migrationID]
	return exists, nil
}

// GetMigrationInfo gets the execution info for a specific migration
func (s *Storage) GetMigrationInfo(ctx *log.Context, migrationID string) (*MigrationInfo, error) {
	const functionName = "data_migration.Storage.GetMigrationInfo"

	// Get executed migrations
	migrations, err := s.GetExecutedMigrations(ctx)
	if err != nil {
		return nil, errors.Wrap(err, functionName)
	}

	// Get migration info from map
	info, exists := migrations[migrationID]
	if !exists {
		return nil, nil
	}

	return &info, nil
}
```

This implementation now uses a map for the migration history, which makes lookups by migration ID much more efficient (O(1) instead of O(n)). The rest of the functionality remains the same, but performance will be better, especially as the number of migrations grows.


