// registry maintains the collection of all available migrations.
type registry struct {
  migrations []Migration
  lookup     map[string]Migration
}

// newRegistry creates a new migration registry.
func newRegistry() *registry {
  return &registry{
    migrations: []Migration{},
    lookup:     make(map[string]Migration),
  }
}

// Register adds a migration to the registry.
func (r *registry) Register(migration Migration) {
  // Add to lookup map for quick retrieval by ID
  r.lookup[migration.ID()] = migration

	r.migrations = append(r.migrations, migration)
}

// GetAll returns all registered migrations in order.
func (r *registry) GetAll() []Migration {
  return r.migrations
}

// DefaultRegistry is the global migration registry where
// migrations should be registered.
var DefaultRegistry = newRegistry()

// RunMigrations executes all pending migrations after DB publish
// This function should be called after indices and scripts are published.
func RunMigrations(
  logContext *log.Context,
  client repository.NoSqlRepository,
  consulClient consul.Client,
) error {
  const functionName = "data_migration.RunMigrations"

	log.Infow(logContext, "Initializing data migration framework")

	// Create storage for migration history
	storage := newStorage(consulClient)

	// Create runner using the default registry
	runner := newRunner(DefaultRegistry, storage, client)

	// Run all pending migrations
	if err := runner.RunPendingMigrations(logContext); err != nil {
	return errors.Wrap(err, functionName)
	}

	return nil
}
