// In data-migration/registry.go

// isRegistrationInitialized tracks whether migrations have been registered
var isRegistrationInitialized bool = false

// MarkRegistrationsInitialized marks the registration process as completed
// This must be called after all migrations are registered
func MarkRegistrationsInitialized() {
    isRegistrationInitialized = true
}

// RunMigrations executes all pending migrations after DB publish
// This function should be called after indices and scripts are published.
func RunMigrations(
    logContext *log.Context,
    client repository.NoSqlRepository,
    consulClient consul.Client,
) error {
    const functionName = "data_migration.RunMigrations"

    // Enforce that registrations must be initialized before running migrations
    if !isRegistrationInitialized {
        return errors.New(functionName + ": migration registrations are not initialized, call MarkRegistrationsInitialized first")
    }

    // Check if any migrations are registered
    if len(DefaultRegistry.GetAll()) == 0 {
        log.Infow(logContext, "No migrations registered, skipping migration process")
        return nil
    }

    log.Infow(logContext, "Initializing data migration framework")

    // Create storage for migration history
    storage := newStorage(consulClient)

    // Create runner using the default registry
    runner := newRunner(DefaultRegistry, storage, client)

    // Run all pending migrations
    if err := runner.runPendingMigrations(logContext); err != nil {
        return errors.Wrap(err, functionName)
    }

    return nil
}
