// RunPendingMigrations executes all pending migrations.
func (r *runner) RunPendingMigrations(ctx *log.Context) error {
const functionName = "data_migration.RunPendingMigrations"

	log.Infow(ctx, "Starting data migrations")

	// Load migration history
	executedMigrations, err := r.storage.GetExecutedMigrations(ctx)
	if err != nil {
	return errors.Wrapf(err, "%s: Failed to load migration history", functionName)
	}

	log.Infow(ctx, "Loaded migration history", "executed_count", len(executedMigrations))

	// Get all migrations to execute
	registeredMigrations := r.registry.GetAll()

	// Track if we've modified the history
	historyModified := false

	// Execute each migration if it hasn't been executed yet
	for _, migration := range registeredMigrations {
	migrationID := migration.ID()

		// Check if already executed
		_, alreadyExecuted := executedMigrations[migrationID]

		if alreadyExecuted {
		log.Infow(ctx, "Skipping already executed migration",
		"migration_id", migrationID,
		"migration_name", migration.Name(),
		"migration_version", migration.Version())
		continue
		}

		log.Infow(ctx, "Executing migration",
		"migration_id", migrationID,
		"migration_name", migration.Name(),
		"migration_version", migration.Version(),
		"migration_description", migration.Description())

		startTime := time.Now()

		// Execute the migration
		if err := migration.Execute(ctx, r.client); err != nil {
		return errors.Wrapf(err, "%s: Failed to execute migration %s",
		functionName, migrationID)
		}

		// Create migration info
		info := migrationInfo{
		Name:        migration.Name(),
		Version:     migration.Version(),
		ID:          migrationID,
		Description: migration.Description(),
		ExecutedAt:  time.Now(),
		DurationMs:  time.Since(startTime).Milliseconds(),
		}

		// Add to our local copy of executed migrations
		executedMigrations[migrationID] = info
		historyModified = true

		log.Infow(ctx, "Migration completed successfully",
		"migration_id", migrationID,
		"migration_name", migration.Name(),
		"migration_version", migration.Version(),
		"duration_ms", info.DurationMs)
		}

	// Save updated history back to Consul if we made changes
	if historyModified {
	history := migrationHistory{
	Migrations: executedMigrations,
	}

		if err := r.storage.SaveMigrationHistory(ctx, history); err != nil {
		return errors.Wrapf(err, "%s: Failed to save updated migration history", functionName)
		}
		}

	log.Infow(ctx, "Completed all data migrations")

	return nil
	}
