package data_migration

import (
	"airwatch/uem/gumdrop-ingestion/internal/pkg/consul"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"encoding/json"
	"time"

	"github.com/pkg/errors"
)

const (
	// MigrationHistoryKey is the Consul key where migration history is stored
	MigrationHistoryKey = "migration_history"
)

// storage handles persistence of migration history
type storage struct {
	consulClient consul.Client
}

// migrationInfo represents metadata about a migration that has been executed.
type migrationInfo struct {
	Name        string    `json:"name"`
	Version     int       `json:"version"`
	ID          string    `json:"id"`
	Description string    `json:"description"`
	ExecutedAt  time.Time `json:"executed_at"`
	DurationMs  int64     `json:"duration_ms"`
}

// migrationHistory stores information about all executed migrations using a map for faster lookups.
type migrationHistory struct {
	// Map from migration ID to migration info
	Migrations map[string]migrationInfo `json:"migrations"`
}

// newStorage creates a new migration storage
func newStorage(consulClient consul.Client) *storage {
	return &storage{
		consulClient: consulClient,
	}
}

// GetExecutedMigrations retrieves the map of migrations that have been executed
func (s *storage) GetExecutedMigrations(ctx *log.Context) (map[string]migrationInfo, error) {
	const functionName = "data_migration.GetExecutedMigrations"

	// Get migration history from Consul
	kvPair, err := s.consulClient.GetKey(MigrationHistoryKey)
	if err != nil {
		return nil, errors.Wrap(err, functionName)
	}

	// If key doesn't exist, return empty history
	if kvPair == nil || len(kvPair.Value) == 0 {
		return make(map[string]migrationInfo), nil
	}

	// Unmarshal migration history
	var history migrationHistory
	if err := json.Unmarshal(kvPair.Value, &history); err != nil {
		return nil, errors.Wrap(err, functionName)
	}

	if history.Migrations == nil {
		return make(map[string]migrationInfo), nil
	}

	return history.Migrations, nil
}

// SaveMigrationHistory saves the entire migration history
func (s *storage) SaveMigrationHistory(ctx *log.Context, history migrationHistory) error {
	const functionName = "data_migration.SaveMigrationHistory"

	// Save history to Consul
	if err := s.consulClient.PutKey(MigrationHistoryKey, history); err != nil {
		return errors.Wrap(err, functionName)
	}

	return nil
}
