package data_migration

import (
    "airwatch/uem/gumdrop-ingestion/internal/pkg/consul"
    "airwatch/uem/gumdrop-ingestion/pkg/log"
    "airwatch/uem/gumdrop-ingestion/pkg/repository"
    "encoding/json"
    "time"

    "github.com/pkg/errors"
)

const MigrationHistoryKey = "migration_history"

// registry maintains the collection of migrations
type registry struct {
    migrations []Migration
    lookup     map[string]Migration
}

// Global registry for migrations
var defaultRegistry = &registry{
    migrations: []Migration{},
    lookup:     make(map[string]Migration),
}

// Register adds a migration to the registry
func Register(migration Migration) {
    defaultRegistry.lookup[migration.ID()] = migration
    defaultRegistry.migrations = append(defaultRegistry.migrations, migration)
}

// RunMigrations executes all pending migrations
func RunMigrations(
    logContext *log.Context,
    client repository.NoSqlRepository,
    consulClient consul.Client,
) error {
    const functionName = "data_migration.RunMigrations"

    log.Infow(logContext, "Initializing data migration framework")

    // Get all migrations to execute
    registeredMigrations := defaultRegistry.migrations

    if len(registeredMigrations) == 0 {
        log.Infow(logContext, "No migrations registered, skipping migration process")
        return nil
    }

    // Load migration history
    executedMigrations, err := getExecutedMigrations(logContext, consulClient)
    if err != nil {
        return errors.Wrapf(err, "%s: Failed to load migration history", functionName)
    }

    log.Infow(logContext, "Loaded migration history", "executed_count", len(executedMigrations))

    // Track if we've modified the history
    historyModified := false

    // Execute each migration if it hasn't been executed yet
    for _, migration := range registeredMigrations {
        migrationID := migration.ID()

        // Check if already executed
        _, alreadyExecuted := executedMigrations[migrationID]

        if alreadyExecuted {
            log.Infow(logContext, "Skipping already executed migration",
                "migration_id", migrationID,
                "migration_name", migration.Name(),
                "migration_version", migration.Version())
            continue
        }

        log.Infow(logContext, "Executing migration",
            "migration_id", migrationID,
            "migration_name", migration.Name(),
            "migration_version", migration.Version(),
            "migration_description", migration.Description())

        startTime := time.Now()

        // Execute the migration
        if err := migration.Execute(logContext, client); err != nil {
            return errors.Wrapf(err, "%s: Failed to execute migration %s",
                functionName, migrationID)
        }

        // Create migration info
        info := migrationInfo{
            Name:        migration.Name(),
            Version:     migration.Version(),
            ID:          migrationID,
            Description: migration.Description(),
            ExecutedAt:  time.Now(),
            DurationMs:  time.Since(startTime).Milliseconds(),
        }

        // Add to our local copy of executed migrations
        executedMigrations[migrationID] = info
        historyModified = true

        log.Infow(logContext, "Migration completed successfully",
            "migration_id", migrationID,
            "migration_name", migration.Name(),
            "migration_version", migration.Version(),
            "duration_ms", info.DurationMs)
    }

    // Save updated history back to Consul if we made changes
    if historyModified {
        history := migrationHistory{
            Migrations: executedMigrations,
        }

        if err := saveHistory(logContext, consulClient, history); err != nil {
            return errors.Wrapf(err, "%s: Failed to save updated migration history", functionName)
        }
    }

    log.Infow(logContext, "Completed all data migrations")

    return nil
}

// getExecutedMigrations retrieves the migration history from Consul
func getExecutedMigrations(ctx *log.Context, client consul.Client) (map[string]migrationInfo, error) {
    kvPair, err := client.GetKey(MigrationHistoryKey)
    if err != nil {
        return nil, errors.Wrap(err, "data_migration.getExecutedMigrations")
    }

    if kvPair == nil || len(kvPair.Value) == 0 {
        return make(map[string]migrationInfo), nil
    }

    var history migrationHistory
    if err := json.Unmarshal(kvPair.Value, &history); err != nil {
        return nil, errors.Wrap(err, "data_migration.getExecutedMigrations")
    }

    if history.Migrations == nil {
        return make(map[string]migrationInfo), nil
    }

    return history.Migrations, nil
}

// saveHistory saves the migration history to Consul
func saveHistory(ctx *log.Context, client consul.Client, history migrationHistory) error {
    if err := client.PutKey(MigrationHistoryKey, history); err != nil {
        return errors.Wrap(err, "data_migration.saveHistory")
    }
    return nil
}
```

