package data_migration

import (
	"airwatch/uem/gumdrop-ingestion/internal/pkg/consul"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"airwatch/uem/gumdrop-ingestion/pkg/repository"
	"time"

	"github.com/pkg/errors"
)

// runner coordinates the migration process
type runner struct {
	registry *registry
	storage  *storage
	client   repository.NoSqlRepository
}

// newRunner creates a new migration runner
func newRunner(registry *registry, storage *storage, client repository.NoSqlRepository) *runner {
	return &runner{
		registry: registry,
		storage:  storage,
		client:   client,
	}
}

// RunMigrations is the public API for running migrations
func RunMigrations(
	logContext *log.Context,
	client repository.NoSqlRepository,
	consulClient consul.Client,
) error {
	const functionName = "data_migration.RunMigrations"

	log.Infow(logContext, "Initializing data migration framework")

	storage := newStorage(consulClient)
	return newRunner(defaultRegistry, storage, client).runMigrations(logContext)
}

// runMigrations executes all pending migrations
func (r *runner) runMigrations(ctx *log.Context) error {
	const functionName = "data_migration.runner.runMigrations"

	// Get all migrations to execute
	migrations := r.registry.GetAll()
	if len(migrations) == 0 {
		log.Infow(ctx, "No migrations registered, skipping migration process")
		return nil
	}

	// Load migration history
	executedMigrations, err := r.storage.GetExecutedMigrations(ctx)
	if err != nil {
		return errors.Wrapf(err, "%s: Failed to load migration history", functionName)
	}

	log.Infow(ctx, "Loaded migration history", "executed_count", len(executedMigrations))

	// Check for pending migrations
	pendingMigrations := r.findPendingMigrations(migrations, executedMigrations)
	if len(pendingMigrations) == 0 {
		log.Infow(ctx, "All migrations have already been executed", 
			"total_migrations", len(migrations))
		return nil
	}

	log.Infow(ctx, "Found pending migrations", "count", len(pendingMigrations))

	// Execute pending migrations
	if err := r.executeMigrations(ctx, pendingMigrations, executedMigrations); err != nil {
		return errors.Wrapf(err, "%s: Migration execution failed", functionName)
	}

	log.Infow(ctx, "Completed all data migrations", "executed_count", len(pendingMigrations))
	return nil
}

// findPendingMigrations returns migrations that haven't been executed yet
func (r *runner) findPendingMigrations(
	migrations []Migration, 
	executedMigrations map[string]migrationInfo,
) []Migration {
	var pending []Migration

	for _, migration := range migrations {
		if _, executed := executedMigrations[migration.ID()]; !executed {
			pending = append(pending, migration)
		}
	}

	return pending
}

// executeMigrations runs the given migrations and updates history
func (r *runner) executeMigrations(
	ctx *log.Context,
	migrations []Migration,
	executedMigrations map[string]migrationInfo,
) error {
	const functionName = "data_migration.runner.executeMigrations"

	// Return early if no migrations to run
	if len(migrations) == 0 {
		return nil
	}

	// Execute each migration
	for _, migration := range migrations {
		log.Infow(ctx, "Executing migration",
			"migration_id", migration.ID(),
			"migration_name", migration.Name(),
			"migration_version", migration.Version(),
			"migration_description", migration.Description())

		startTime := time.Now()

		// Execute the migration
		if err := migration.Execute(ctx, r.client); err != nil {
			return errors.Wrapf(err, "%s: Failed to execute migration %s",
				functionName, migration.ID())
		}

		// Record migration execution
		executedMigrations[migration.ID()] = migrationInfo{
			Name:        migration.Name(),
			Version:     migration.Version(),
			ID:          migration.ID(),
			Description: migration.Description(),
			ExecutedAt:  time.Now(),
			DurationMs:  time.Since(startTime).Milliseconds(),
		}

		log.Infow(ctx, "Migration completed successfully",
			"migration_id", migration.ID(),
			"migration_name", migration.Name(),
			"migration_version", migration.Version(),
			"duration_ms", time.Since(startTime).Milliseconds())

		// Save history after each successful migration
		history := migrationHistory{Migrations: executedMigrations}
		if err := r.storage.SaveMigrationHistory(ctx, history); err != nil {
			return errors.Wrapf(err, "%s: Failed to save migration history after %s",
				functionName, migration.ID())
		}
	}

	return nil
}
