```go
// Register adds a migration to the registry with validation
func Register(migration Migration) error {
    // Validate the migration
    if migration == nil {
        return errors.New("migration cannot be nil")
    }

    if migration.Name() == "" {
        return fmt.Errorf("migration name cannot be empty: %v", migration)
    }

    if migration.Version() < 1 {
        return fmt.Errorf("migration version must be greater than 0: %s", migration.Name())
    }

    // Check for duplicates
    id := migration.ID()
    if _, exists := migrationRegistry.lookup[id]; exists {
        return fmt.Errorf("migration with ID %s is already registered", id)
    }

    // Add to registry
    migrationRegistry.lookup[id] = migration
    migrationRegistry.migrations = append(migrationRegistry.migrations, migration)

    return nil
}
```

